/**팝업게시판 리스트*/
SELECT A.* FROM (

	SELECT A.*
	FROM t_popup A
	WHERE 1 = 1


) A
ORDER BY IDX desc
limit #{firstRecordIndex},#{recordCountPerPage}

mapper.update:
/** 통합게시판 수정 */
UPDATE t_popup 
SET
	TITLE=#{title}
	,CONTENT=#{content}
	,START_DTIME=#{startDtime}
	,END_DTIME=#{endDtime}
	,HEIGHT=#{height},WIDTH=#{width},POS_X=#{posX},POS_Y=#{posY}

	,IMG=#{img}

	,STATUS=#{status}
WHERE
	IDX=#{idx}
